import React, { useEffect, useState } from "react";
import Navbar from "../components/Navbar";
import api from "../services/api";

function JournalPage() {
  const [energyBalance, setEnergyBalance] = useState([]);

  useEffect(() => {
    const loadData = async () => {
      try {
        const res = await api.get("/energy-balance");
        setEnergyBalance(res.data);
      } catch (err) {
        console.log(err);
      }
    };

    loadData();
  }, []);

  return (
    <div>
      <Navbar />
      <div className="page-container">
        <h2>Nhật kí dinh dưỡng</h2>

        {energyBalance.length === 0 ? (
          <p>Chưa có dữ liệu nhật kí.</p>
        ) : (
          energyBalance.map((item, index) => (
            <div key={index} className="card">
              <p><strong>Ngày:</strong> {item.meal_date}</p>
              <p><strong>Tổng calo:</strong> {item.total_calories}</p>
              <p><strong>TDEE:</strong> {item.TDEE}</p>
              <p><strong>Chênh lệch:</strong> {item.calorie_balance}</p>
              <p><strong>Trạng thái:</strong> {item.energy_status}</p>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default JournalPage;
